 1	import { useState, useEffect } from 'react'
 2	import { supabase } from '../lib/supabase'
 3	import type { User, Session } from '@supabase/supabase-js'
 4	
 5	export function useAuth() {
 6	  const [user, setUser] = useState<User | null>(null)
 7	  const [session, setSession] = useState<Session | null>(null)
 8	  const [loading, setLoading] = useState(true)
 9	
10	  useEffect(() => {
11	    // Get initial session
12	    supabase.auth.getSession().then(({ data: { session } }) => {
13	      setSession(session)
14	      setUser(session?.user ?? null)
15	      setLoading(false)
16	    })
17	
18	    // Listen for auth changes
19	    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
20	      setSession(session)
21	      setUser(session?.user ?? null)
22	      setLoading(false)
23	    })
24	
25	    return () => subscription.unsubscribe()
26	  }, [])
27	
28	  return { user, session, loading }
29	}
30	
31	export async function signInWithPhone(phone: string) {
32	  const { data, error } = await supabase.auth.signInWithOtp({
33	    phone,
34	    options: {
35	      shouldCreateUser: true,
36	    },
37	  })
38	  return { data, error }
39	}
40	
41	export async function verifyOtp(phone: string, token: string) {
42	  const { data, error } = await supabase.auth.verifyOtp({
43	    phone,
44	    token,
45	    type: 'sms',
46	  })
47	  return { data, error }
48	}
49	
50	export async function signOut() {
51	  const { error } = await supabase.auth.signOut()
52	  return { error }
53	}
54	
55	export async function getCurrentUser() {
56	  const { data: { user } } = await supabase.auth.getUser()
57	  return user
58	}

