 * WebSocket Event Types
 * Matches the backend WebSocketEventType enum
 */
export enum WebSocketEventType {
  // Order Events
  ORDER_CREATED = 'order_created',
  ORDER_STATUS_UPDATED = 'order_status_updated',
  ORDER_ASSIGNED = 'order_assigned',
  ORDER_CANCELLED = 'order_cancelled',

  // Driver Events
  DRIVER_LOCATION_UPDATE = 'driver_location_update',
  DRIVER_STATUS_UPDATE = 'driver_status_update',
  DRIVER_ASSIGNED = 'driver_assigned',

  // Delivery Events
  DELIVERY_COMPLETED = 'delivery_completed',
  DELIVERY_FAILED = 'delivery_failed',
  ESTIMATED_ARRIVAL = 'estimated_arrival',

  // Messaging Events
  NEW_MESSAGE = 'new_message',
  MESSAGE_READ = 'message_read',

  // System Events
  PING = 'ping',
  PONG = 'pong',
  HEARTBEAT = 'heartbeat',
  AUTHENTICATED = 'authenticated',
  ERROR = 'error',
  CONNECTED = 'connected',
  DISCONNECTED = 'disconnected',

  // Client Events
  SUBSCRIBE = 'subscribe',
  UNSUBSCRIBE = 'unsubscribe',
  SUBSCRIBED = 'subscribed',
  UNSUBSCRIBED = 'unsubscribed',
  GET_LOCATION = 'get_location',
  GET_STATUS = 'get_status',
}

/**
 * Room Types
 */
export enum RoomType {
  ORDER = 'order',
  DRIVER = 'driver',
  MERCHANT = 'merchant',
  USER = 'user',
  ADMIN = 'admin',
}

/**
 * Order Status
 */
export enum OrderStatus {
  PENDING = 'pending',
  CONFIRMED = 'confirmed',
  PREPARING = 'preparing',
  READY = 'ready',
  PICKED_UP = 'picked_up',
  IN_TRANSIT = 'in_transit',
  DELIVERED = 'delivered',
  CANCELLED = 'cancelled',
}

/**
 * Driver Status
 */
export enum DriverStatus {
  OFFLINE = 'offline',
  AVAILABLE = 'available',
  BUSY = 'busy',
  BREAK = 'break',
}

/**
 * Base WebSocket Message
 */
export interface WebSocketMessage {
  type: WebSocketEventType | string;
  timestamp?: string;
  [key: string]: any;
}

/**
 * Location Data
 */
export interface LocationData {
  latitude: number;
  longitude: number;
  heading?: number;
  speed?: number;
  last_updated?: string;
}

/**
 * Order Created Event
 */
export interface OrderCreatedEvent extends WebSocketMessage {
  type: WebSocketEventType.ORDER_CREATED;
  order_id: string;
  order: {
    id: string;
    buyer_id: string;
    store_id: string;
    items: Array<{
      product_id: string;
      product_name: string;
      quantity: number;
      unit_price: number;
      total_price: number;
    }>;
    subtotal: number;
    delivery_fee: number;
    total: number;
    status: OrderStatus;
    delivery_info: {
      address_label: string;
      address_line1: string;
      address_line2?: string;
      city: string;
      area?: string;
      latitude?: number;
      longitude?: number;
      recipient_phone?: string;
      delivery_instructions?: string;
    };
    created_at: string;
  };
}

/**
 * Order Status Updated Event
 */
export interface OrderStatusUpdatedEvent extends WebSocketMessage {
  type: WebSocketEventType.ORDER_STATUS_UPDATED;
  order_id: string;
  status: OrderStatus;
  status_history?: Array<{
    status: OrderStatus;
    timestamp: string;
    actor?: string;
  }>;
}

/**
 * Driver Location Update Event
 */
export interface DriverLocationUpdateEvent extends WebSocketMessage {
  type: WebSocketEventType.DRIVER_LOCATION_UPDATE;
  order_id?: string;
  rider_id?: string;
  rider_location: LocationData;
}

/**
 * Driver Assigned Event
 */
export interface DriverAssignedEvent extends WebSocketMessage {
  type: WebSocketEventType.DRIVER_ASSIGNED;
  order_id: string;
  rider_id: string;
  rider_name?: string;
  rider_phone?: string;
  rider_location?: LocationData;
}

/**
 * Delivery Completed Event
 */
export interface DeliveryCompletedEvent extends WebSocketMessage {
  type: WebSocketEventType.DELIVERY_COMPLETED;
  order_id: string;
  rider_id?: string;
  message?: string;
}

/**
 * New Message Event
 */
export interface NewMessageEvent extends WebSocketMessage {
  type: WebSocketEventType.NEW_MESSAGE;
  sender_id: string;
  order_id?: string;
  message: string;
}

/**
 * Connected Event
 */
export interface ConnectedEvent extends WebSocketMessage {
  type: WebSocketEventType.CONNECTED;
  room_type?: RoomType;
  room_id?: string;
  message?: string;
  user_id?: string;
  role?: string;
}

/**
 * Authenticated Event
 */
export interface AuthenticatedEvent extends WebSocketMessage {
  type: WebSocketEventType.AUTHENTICATED;
  user_id: string;
  role: string;
}

/**
 * Error Event
 */
export interface ErrorEvent extends WebSocketMessage {
  type: WebSocketEventType.ERROR;
  message: string;
  code?: number;
}

/**
 * Heartbeat/Pong Event
 */
export interface HeartbeatEvent extends WebSocketMessage {
  type: WebSocketEventType.HEARTBEAT | WebSocketEventType.PONG;
}

/**
 * Subscribe/Unsubscribe Events
 */
export interface SubscribeEvent extends WebSocketMessage {
  type: WebSocketEventType.SUBSCRIBE | WebSocketEventType.UNSUBSCRIBE;
  room_type: RoomType;
  room_id: string;
  is_owner?: boolean;
}

/**
 * Union type for all WebSocket events
 */
export type WebSocketEvent =
  | OrderCreatedEvent
  | OrderStatusUpdatedEvent
  | DriverLocationUpdateEvent
  | DriverAssignedEvent
  | DeliveryCompletedEvent
  | NewMessageEvent
  | ConnectedEvent
  | AuthenticatedEvent
  | ErrorEvent
  | HeartbeatEvent
  | SubscribeEvent
  | WebSocketMessage;

/**
 * WebSocket Connection Status
 */
export enum ConnectionStatus {
  CONNECTING = 'connecting',
  CONNECTED = 'connected',
  DISCONNECTED = 'disconnected',
  RECONNECTING = 'reconnecting',
  ERROR = 'error',
}

/**
 * WebSocket Options
 */
export interface WebSocketOptions {
  autoReconnect?: boolean;
  reconnectAttempts?: number;
  reconnectInterval?: number;
  heartbeatInterval?: number;
  onConnect?: () => void;
  onDisconnect?: () => void;
  onError?: (error: Event) => void;
  onMessage?: (event: WebSocketEvent) => void;
}

/**
 * Order with real-time updates
 */
export interface OrderWithRealtime {
  id: string;
  buyer_id: string;
  store_id: string;
  rider_id?: string;
  items: Array<{
    product_id: string;
    product_name: string;
    quantity: number;
    unit_price: number;
    total_price: number;
  }>;
  subtotal: number;
  delivery_fee: number;
  total: number;
  status: OrderStatus;
  status_history: Array<{
    status: OrderStatus;
    timestamp: string;
    actor?: string;
  }>;
  delivery_info: {
    address_label: string;
    address_line1: string;
    address_line2?: string;
    city: string;
    area?: string;
    latitude?: number;
    longitude?: number;
    recipient_phone?: string;
    delivery_instructions?: string;
  };
  created_at: string;
  confirmed_at?: string;
  delivered_at?: string;
  estimated_delivery?: string;
  payment_method: string;
  payment_status: string;
  rider_location?: LocationData;
  rider_name?: string;
  rider_phone?: string;
}

/**
 * Notification types for toast messages
 */
export enum NotificationType {
  SUCCESS = 'success',
  ERROR = 'error',
  WARNING = 'warning',
  INFO = 'info',
}

/**
 * Notification data
 */
export interface NotificationData {
  id: string;
  type: NotificationType;
  title: string;
  message: string;
  timestamp: number;
  orderId?: string;
  autoDismiss?: boolean;
  dismissAfter?: number;
}
"}

{"path": "/home/teacherchris37/frontend/src/services/websocket.ts", "content": "/**
 * WebSocket Service
 * Handles real-time communication with the backend
 */
import {
  WebSocketEventType,
  RoomType,
  ConnectionStatus,
  WebSocketOptions,
  WebSocketEvent,
  LocationData,
  OrderStatus,
} from '../types/websocket';

/**
 * Get the WebSocket base URL from the API URL
 */
const getWebSocketURL = (): string => {
  const apiUrl = import.meta.env.VITE_API_URL || 'http://localhost:8000';
  const wsProtocol = apiUrl.startsWith('https') ? 'wss' : 'ws';
  const baseUrl = apiUrl.replace(/^https?:\/\//, '');
  return `${wsProtocol}://${baseUrl}`;
};

/**
 * Get authentication token from localStorage
 */
const getAuthToken = (): string | null => {
  return localStorage.getItem('access_token');
};

/**
 * WebSocket Service Class
 * Manages WebSocket connections with automatic reconnection
 */
class WebSocketService {
  private ws: WebSocket | null = null;
  private url: string = '';
  private options: WebSocketOptions = {};
  private reconnectCount: number = 0;
  private reconnectTimer: NodeJS.Timeout | null = null;
  private heartbeatTimer: NodeJS.Timeout | null = null;
  private pongReceived: boolean = true;
  private messageHandlers: Map<string, Set<(event: WebSocketEvent) => void>> = new Map();
  private connectionStatus: ConnectionStatus = ConnectionStatus.DISCONNECTED;
  private subscribedRooms: Set<string> = new Set();
  private pendingMessages: Array<WebSocketEvent> = [];

  // Default options
  private defaultOptions: WebSocketOptions = {
    autoReconnect: true,
    reconnectAttempts: 5,
    reconnectInterval: 3000,
    heartbeatInterval: 25000,
  };

  /**
   * Get current connection status
   */
  getStatus(): ConnectionStatus {
    return this.connectionStatus;
  }

  /**
   * Check if connected
   */
  isConnected(): boolean {
    return this.connectionStatus === ConnectionStatus.CONNECTED && 
           this.ws?.readyState === WebSocket.OPEN;
  }

  /**
   * Connect to WebSocket
   */
  connect(endpoint: string = '/ws', options: WebSocketOptions = {}): Promise<void> {
    return new Promise((resolve, reject) => {
      this.options = { ...this.defaultOptions, ...options };

      if (this.isConnected()) {
        resolve();
        return;
      }

      this.connectionStatus = ConnectionStatus.CONNECTING;

      const token = getAuthToken();
      if (!token) {
        this.connectionStatus = ConnectionStatus.ERROR;
        reject(new Error('Authentication token not found'));
        return;
      }

      this.url = `${getWebSocketURL()}${endpoint}?token=${encodeURIComponent(token)}`;

      try {
        this.ws = new WebSocket(this.url);

        this.ws.onopen = () => {
          console.log('[WebSocket] Connected');
          this.connectionStatus = ConnectionStatus.CONNECTED;
          this.reconnectCount = 0;
          this.startHeartbeat();
          this.processPendingMessages();
          this.resubscribeToRooms();
          this.options.onConnect?.();
          resolve();
        };

        this.ws.onmessage = (event) => {
          this.handleMessage(event);
        };

        this.ws.onerror = (error) => {
          console.error('[WebSocket] Error:', error);
          this.connectionStatus = ConnectionStatus.ERROR;
          this.options.onError?.(error);
          reject(error);
        };

        this.ws.onclose = (event) => {
          console.log('[WebSocket] Disconnected:', event.code, event.reason);
          this.connectionStatus = ConnectionStatus.DISCONNECTED;
          this.stopHeartbeat();
          this.options.onDisconnect?.();

          if (this.options.autoReconnect && this.reconnectCount < (this.options.reconnectAttempts || 5)) {
            this.attemptReconnect(endpoint);
          }
        };
      } catch (error) {
        this.connectionStatus = ConnectionStatus.ERROR;
        reject(error);
      }
    });
  }

  /**
   * Disconnect from WebSocket
   */
  disconnect(): void {
    this.options.autoReconnect = false;
    this.stopHeartbeat();

    if (this.reconnectTimer) {
      clearTimeout(this.reconnectTimer);
      this.reconnectTimer = null;
    }

    if (this.ws) {
      this.ws.close(1000, 'Client disconnected');
      this.ws = null;
    }

    this.connectionStatus = ConnectionStatus.DISCONNECTED;
    this.subscribedRooms.clear();
  }

  /**
   * Attempt to reconnect
   */
  private attemptReconnect(endpoint: string): void {
    this.reconnectCount++;
    this.connectionStatus = ConnectionStatus.RECONNECTING;

    console.log(`[WebSocket] Reconnecting... Attempt ${this.reconnectCount}/${this.options.reconnectAttempts}`);

    this.reconnectTimer = setTimeout(() => {
      this.connect(endpoint, this.options).catch(() => {
        // Reconnection failed, will try again if attempts remain
      });
    }, this.options.reconnectInterval);
  }

  /**
   * Start heartbeat interval
   */
  private startHeartbeat(): void {
    if (!this.options.heartbeatInterval) return;

    this.heartbeatTimer = setInterval(() => {
      if (!this.pongReceived) {
        console.log('[WebSocket] No pong received, reconnecting...');
        this.ws?.close(1000, 'Heartbeat timeout');
        return;
      }

      this.pongReceived = false;
      this.send({ type: WebSocketEventType.PING });
    }, this.options.heartbeatInterval);
  }

  /**
   * Stop heartbeat interval
   */
  private stopHeartbeat(): void {
    if (this.heartbeatTimer) {
      clearInterval(this.heartbeatTimer);
      this.heartbeatTimer = null;
    }
  }

  /**
   * Handle incoming message
   */
  private handleMessage(event: MessageEvent): void {
    try {
      const data: WebSocketEvent = JSON.parse(event.data);

      // Handle pong
      if (data.type === WebSocketEventType.PONG) {
        this.pongReceived = true;
        return;
      }

      // Handle heartbeat from server
      if (data.type === WebSocketEventType.HEARTBEAT) {
        this.send({ type: WebSocketEventType.PONG });
        return;
      }

      console.log('[WebSocket] Message received:', data.type);

      // Call global message handler
      this.options.onMessage?.(data);

      // Call specific handlers
      this.callHandlers(data.type, data);

      // Also call wildcard handlers
      this.callHandlers('*', data);
    } catch (error) {
      console.error('[WebSocket] Error parsing message:', error);
    }
  }

  /**
   * Call registered handlers for an event type
   */
  private callHandlers(type: string, data: WebSocketEvent): void {
    const handlers = this.messageHandlers.get(type);
    if (handlers) {
      handlers.forEach((handler) => {
        try {
          handler(data);
        } catch (error) {
          console.error(`[WebSocket] Error in handler for ${type}:`, error);
        }
      });
    }
  }

  /**
   * Send message to server
   */
  send(message: Partial<WebSocketEvent>): boolean {
    if (this.isConnected()) {
      try {
        this.ws!.send(JSON.stringify(message));
        return true;
      } catch (error) {
        console.error('[WebSocket] Send error:', error);
        return false;
      }
    } else {
      // Queue message for later
      this.pendingMessages.push(message as WebSocketEvent);
      return false;
    }
  }

  /**
   * Process pending messages after connection
   */
  private processPendingMessages(): void {
    while (this.pendingMessages.length > 0) {
      const message = this.pendingMessages.shift();
      if (message) {
        this.send(message);
      }
    }
  }

  /**
   * Subscribe to a room
   */
  subscribe(roomType: RoomType, roomId: string, isOwner: boolean = false): void {
    const roomKey = `${roomType}:${roomId}`;
    this.subscribedRooms.add(roomKey);

    this.send({
      type: WebSocketEventType.SUBSCRIBE,
      room_type: roomType,
      room_id: roomId,
      is_owner: isOwner,
    });
  }

  /**
   * Unsubscribe from a room
   */
  unsubscribe(roomType: RoomType, roomId: string): void {
    const roomKey = `${roomType}:${roomId}`;
    this.subscribedRooms.delete(roomKey);

    this.send({
      type: WebSocketEventType.UNSUBSCRIBE,
      room_type: roomType,
      room_id: roomId,
    });
  }

  /**
   * Resubscribe to all rooms after reconnection
   */
  private resubscribeToRooms(): void {
    this.subscribedRooms.forEach((roomKey) => {
      const [roomType, roomId] = roomKey.split(':') as [RoomType, string];
      this.subscribe(roomType, roomId);
    });
  }

  /**
   * Register message handler
   */
  on(type: string, handler: (event: WebSocketEvent) => void): () => void {
    if (!this.messageHandlers.has(type)) {
      this.messageHandlers.set(type, new Set());
    }

    this.messageHandlers.get(type)!.add(handler);

    // Return unsubscribe function
    return () => {
      this.off(type, handler);
    };
  }

  /**
   * Remove message handler
   */
  off(type: string, handler: (event: WebSocketEvent) => void): void {
    const handlers = this.messageHandlers.get(type);
    if (handlers) {
      handlers.delete(handler);
    }
  }

  /**
   * Remove all handlers for a type
   */
  offAll(type?: string): void {
    if (type) {
      this.messageHandlers.delete(type);
    } else {
      this.messageHandlers.clear();
    }
  }

  // =============================================================================
  // Convenience Methods
  // =============================================================================

  /**
   * Connect to order tracking
   */
  trackOrder(orderId: string, onUpdate?: (event: WebSocketEvent) => void): Promise<void> {
    return new Promise((resolve, reject) => {
      const connectAndTrack = () => {
        this.connect(`/track/${orderId}`, {
          ...this.options,
          onConnect: () => {
            this.options.onConnect?.();
            resolve();
          },
          onMessage: (event) => {
            onUpdate?.(event);
            this.options.onMessage?.(event);
          },
        }).catch(reject);
      };

      if (this.isConnected()) {
        this.disconnect();
      }

      connectAndTrack();
    });
  }

  /**
   * Connect as rider
   */
  connectAsRider(
    riderId: string,
    onOrderAssigned?: (event: WebSocketEvent) => void,
    onMessage?: (event: WebSocketEvent) => void
  ): Promise<void> {
    return this.connect(`/rider/${riderId}`, {
      ...this.options,
      onMessage: (event) => {
        if (event.type === WebSocketEventType.DRIVER_ASSIGNED) {
          onOrderAssigned?.(event);
        }
        onMessage?.(event);
      },
    });
  }

  /**
   * Connect as merchant
   */
  connectAsMerchant(
    merchantId: string,
    onNewOrder?: (event: WebSocketEvent) => void,
    onMessage?: (event: WebSocketEvent) => void
  ): Promise<void> {
    return this.connect(`/merchant/${merchantId}`, {
      ...this.options,
      onMessage: (event) => {
        if (event.type === WebSocketEventType.ORDER_CREATED) {
          onNewOrder?.(event);
        }
        onMessage?.(event);
      },
    });
  }

  /**
   * Connect for user notifications
   */
  connectAsUser(
    userId: string,
    onNotification?: (event: WebSocketEvent) => void
  ): Promise<void> {
    return this.connect(`/user/${userId}`, {
      ...this.options,
      onMessage: (event) => {
        onNotification?.(event);
      },
    });
  }

  /**
   * Update driver location
   */
  updateLocation(location: LocationData): boolean {
    return this.send({
      type: WebSocketEventType.DRIVER_LOCATION_UPDATE,
      location,
    });
  }

  /**
   * Update driver status
   */
  updateStatus(status: 'available' | 'busy' | 'offline' | 'break'): boolean {
    return this.send({
      type: WebSocketEventType.DRIVER_STATUS_UPDATE,
      status,
    });
  }

  /**
   * Send chat message
   */
  sendMessage(orderId: string, message: string): boolean {
    return this.send({
      type: WebSocketEventType.NEW_MESSAGE,
      order_id: orderId,
      message,
    });
  }

  /**
   * Accept order (rider)
   */
  acceptOrder(orderId: string): boolean {
    return this.send({
      type: 'accept_order',
      order_id: orderId,
    });
  }

  /**
   * Complete delivery (rider)
   */
  completeDelivery(orderId: string): boolean {
    return this.send({
      type: 'complete_delivery',
      order_id: orderId,
    });
  }

  /**
   * Update order status (merchant)
   */
  updateOrderStatus(orderId: string, status: OrderStatus): boolean {
    return this.send({
      type: WebSocketEventType.ORDER_STATUS_UPDATED,
      order_id: orderId,
      status,
    });
  }

  /**
   * Request current location
   */
  requestLocation(): boolean {
    return this.send({
      type: WebSocketEventType.GET_LOCATION,
    });
  }

  /**
   * Request current order status
   */
  requestStatus(): boolean {
    return this.send({
      type: WebSocketEventType.GET_STATUS,
    });
  }
}

// Create singleton instance
export const websocketService = new WebSocketService();

// Export class for testing or multiple instances
export { WebSocketService };
"}

{"path": "/home/teacherchris37/frontend/src/hooks/useWebSocket.ts", "content": "/**
 * useWebSocket Hook
 * React hook for WebSocket connections with automatic reconnection
 */
import { useEffect, useRef, useState, useCallback, useMemo } from 'react';
import {
  WebSocketEvent,
  WebSocketEventType,
  ConnectionStatus,
  WebSocketOptions,
  OrderStatus,
  LocationData,
  RoomType,
  OrderWithRealtime,
  NotificationData,
  NotificationType,
} from '../types/websocket';
import { websocketService } from '../services/websocket';

/**
 * Options for useWebSocket hook
 */
export interface UseWebSocketOptions extends WebSocketOptions {
  autoConnect?: boolean;
  endpoint?: string;
}

/**
 * Return type for useWebSocket hook
 */
export interface UseWebSocketReturn {
  // Connection state
  status: ConnectionStatus;
  isConnected: boolean;
  isConnecting: boolean;
  error: Error | null;

  // Actions
  connect: () => Promise<void>;
  disconnect: () => void;
  send: (message: Partial<WebSocketEvent>) => boolean;
  subscribe: (roomType: RoomType, roomId: string, isOwner?: boolean) => void;
  unsubscribe: (roomType: RoomType, roomId: string) => void;

  // Event registration
  on: (type: string, handler: (event: WebSocketEvent) => void) => () => void;
  off: (type: string, handler: (event: WebSocketEvent) => void) => void;
}

/**
 * Hook for general WebSocket connection
 */
export function useWebSocket(options: UseWebSocketOptions = {}): UseWebSocketReturn {
  const { autoConnect = false, endpoint = '/ws', ...wsOptions } = options;

  const [status, setStatus] = useState<ConnectionStatus>(ConnectionStatus.DISCONNECTED);
  const [error, setError] = useState<Error | null>(null);
  const handlersRef = useRef<Array<{ type: string; handler: (event: WebSocketEvent) => void }>>([]);

  const isConnected = status === ConnectionStatus.CONNECTED;
  const isConnecting = status === ConnectionStatus.CONNECTING || status === ConnectionStatus.RECONNECTING;

  const connect = useCallback(async () => {
    setError(null);

    try {
      await websocketService.connect(endpoint, {
        ...wsOptions,
        onConnect: () => {
          setStatus(ConnectionStatus.CONNECTED);
          wsOptions.onConnect?.();
        },
        onDisconnect: () => {
          setStatus(ConnectionStatus.DISCONNECTED);
          wsOptions.onDisconnect?.();
        },
        onError: (err) => {
          setStatus(ConnectionStatus.ERROR);
          setError(err instanceof Error ? err : new Error('WebSocket error'));
          wsOptions.onError?.(err);
        },
        onMessage: wsOptions.onMessage,
      });
    } catch (err) {
      setError(err instanceof Error ? err : new Error('Failed to connect'));
      throw err;
    }
  }, [endpoint, wsOptions]);

  const disconnect = useCallback(() => {
    websocketService.disconnect();
    setStatus(ConnectionStatus.DISCONNECTED);
  }, []);

  const send = useCallback((message: Partial<WebSocketEvent>): boolean => {
    return websocketService.send(message);
  }, []);

  const subscribe = useCallback((roomType: RoomType, roomId: string, isOwner: boolean = false) => {
    websocketService.subscribe(roomType, roomId, isOwner);
  }, []);

  const unsubscribe = useCallback((roomType: RoomType, roomId: string) => {
    websocketService.unsubscribe(roomType, roomId);
  }, []);

  const on = useCallback((type: string, handler: (event: WebSocketEvent) => void): (() => void) => {
    handlersRef.current.push({ type, handler });
    return websocketService.on(type, handler);
  }, []);

  const off = useCallback((type: string, handler: (event: WebSocketEvent) => void) => {
    handlersRef.current = handlersRef.current.filter(
      (h) => h.type !== type || h.handler !== handler
    );
    websocketService.off(type, handler);
  }, []);

  // Auto-connect on mount
  useEffect(() => {
    if (autoConnect) {
      connect();
    }

    // Cleanup on unmount
    return () => {
      // Only disconnect if we're the only component using the service
      // This is a simplification - in production, you'd want reference counting
      handlersRef.current.forEach(({ type, handler }) => {
        websocketService.off(type, handler);
      });
    };
  }, [autoConnect, connect]);

  return {
    status,
    isConnected,
    isConnecting,
    error,
    connect,
    disconnect,
    send,
    subscribe,
    unsubscribe,
    on,
    off,
  };
}

/**
 * Hook for tracking a specific order
 */
export interface UseOrderTrackingOptions {
  orderId: string;
  onStatusUpdate?: (status: OrderStatus, event: WebSocketEvent) => void;
  onLocationUpdate?: (location: LocationData, event: WebSocketEvent) => void;
  onDriverAssigned?: (driverId: string, event: WebSocketEvent) => void;
  onDeliveryComplete?: (event: WebSocketEvent) => void;
  onError?: (error: Error) => void;
}

export interface UseOrderTrackingReturn {
  order: OrderWithRealtime | null;
  isConnected: boolean;
  isConnecting: boolean;
  error: Error | null;
  connect: () => Promise<void>;
  disconnect: () => void;
  requestLocation: () => void;
  requestStatus: () => void;
}

export function useOrderTracking(options: UseOrderTrackingOptions): UseOrderTrackingReturn {
  const { 
    orderId, 
    onStatusUpdate, 
    onLocationUpdate, 
    onDriverAssigned,
    onDeliveryComplete,
    onError,
  } = options;

  const [order, setOrder] = useState<OrderWithRealtime | null>(null);
  const [isConnected, setIsConnected] = useState(false);
  const [isConnecting, setIsConnecting] = useState(false);
  const [error, setError] = useState<Error | null>(null);

  const connect = useCallback(async () => {
    if (!orderId) return;

    setIsConnecting(true);
    setError(null);

    try {
      await websocketService.trackOrder(orderId, (event) => {
        switch (event.type) {
          case WebSocketEventType.CONNECTED:
            setIsConnected(true);
            setIsConnecting(false);
            if (event.order) {
              setOrder((prev) => ({ ...prev, ...event.order } as OrderWithRealtime));
            }
            break;

          case WebSocketEventType.ORDER_STATUS_UPDATED:
            setOrder((prev) => 
              prev ? { ...prev, status: event.status, status_history: event.status_history || [] } : null
            );
            onStatusUpdate?.(event.status, event);
            break;

          case WebSocketEventType.DRIVER_LOCATION_UPDATE:
            if (event.rider_location) {
              setOrder((prev) =>
                prev ? { ...prev, rider_location: event.rider_location! } : null
              );
              onLocationUpdate?.(event.rider_location, event);
            }
            break;

          case WebSocketEventType.DRIVER_ASSIGNED:
            setOrder((prev) =>
              prev ? { 
                ...prev, 
                rider_id: event.rider_id,
                rider_name: event.rider_name,
                rider_phone: event.rider_phone,
                rider_location: event.rider_location,
              } : null
            );
            onDriverAssigned?.(event.rider_id!, event);
            break;

          case WebSocketEventType.DELIVERY_COMPLETED:
            setOrder((prev) =>
              prev ? { ...prev, status: OrderStatus.DELIVERED } : null
            );
            onDeliveryComplete?.(event);
            break;

          case WebSocketEventType.ERROR:
            setError(new Error(event.message || 'WebSocket error'));
            onError?.(new Error(event.message || 'WebSocket error'));
            break;
        }
      });
    } catch (err) {
      setIsConnecting(false);
      setError(err instanceof Error ? err : new Error('Failed to connect'));
      onError?.(err instanceof Error ? err : new Error('Failed to connect'));
    }
  }, [orderId, onStatusUpdate, onLocationUpdate, onDriverAssigned, onDeliveryComplete, onError]);

  const disconnect = useCallback(() => {
    websocketService.disconnect();
    setIsConnected(false);
    setOrder(null);
  }, []);

  const requestLocation = useCallback(() => {
    websocketService.requestLocation();
  }, []);

  const requestStatus = useCallback(() => {
    websocketService.requestStatus();
  }, []);

  // Auto-connect when orderId changes
  useEffect(() => {
    if (orderId) {
      connect();
    }

    return () => {
      disconnect();
    };
  }, [orderId]);

  return {
    order,
    isConnected,
    isConnecting,
    error,
    connect,
    disconnect,
    requestLocation,
    requestStatus,
  };
}

